import { evaluateScript } from "./servers/chrome-devtools/index.js";

const result = await evaluateScript({
  script: `function() {
    // Find the open count from the "Open" tab in the issue filter bar
    // It typically looks like "1,234 Open" as a link or button

    // Search all text nodes for open count pattern
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
    const textNodes = [];
    let node;
    while (node = walker.nextNode()) {
      const text = node.textContent.trim();
      if (text.length > 0 && text.length < 100) {
        textNodes.push(text);
      }
    }

    const openPattern = textNodes.filter(t => /\d[\d,]*\s+Open|Open\s+\d[\d,]*/.test(t));

    // Look for the specific issue-list header area
    const issueListHeader = document.querySelector('[aria-label="Issues"], .js-check-all-container');
    const headerText = issueListHeader?.textContent?.trim()?.substring(0, 200);

    // Check the specific element that GitHub uses for issue count
    // Usually it's in the form of "1,234 Open" in a link
    const allA = [...document.querySelectorAll('a[href*="/issues"]')];
    const openCountLinks = allA
      .filter(a => {
        const text = a.textContent.trim();
        return /\d[\d,]+\s+Open|\d+\s+Open/.test(text);
      })
      .map(a => ({ text: a.textContent.trim().substring(0, 100), href: a.href.substring(0, 100) }));

    return {
      openPattern,
      openCountLinks,
      headerText,
    };
  }`
});

