cat << 'EOF' > extract_full.ts
import { evaluateScript } from "./servers/chrome-devtools/index.js";

const result = await evaluateScript({
  script: `function() {
    const rows = Array.from(document.querySelectorAll('table.wikitable tbody tr'));
    const data = {};
    let currentYear = null;

    for (const row of rows) {
      const cells = row.querySelectorAll('td, th');
      if (!cells.length) continue;

      // Check if first cell is a year
      const firstCell = cells[0].textContent.trim();
      const yearMatch = firstCell.match(/^(\\d{4})$/);

      if (yearMatch) {
        currentYear = yearMatch[1];
        if (parseInt(currentYear) >= 2023) {
          if (!data[currentYear]) data[currentYear] = { laureates: [], rationale: '' };
          // Name is usually 2nd or 3rd cell; rationale somewhere after
          const allText = Array.from(cells).map(c => c.textContent.trim());
          data[currentYear].laureates.push(allText[2] || allText[1]);
          data[currentYear].rationale = allText[4] || allText[3] || '';
        }
      } else if (currentYear && parseInt(currentYear) >= 2023) {
        // continuation row for same year
        const allText = Array.from(cells).map(c => c.textContent.trim());
        // laureate name is usually first cell in continuation row
        data[currentYear].laureates.push(allText[1] || allText[0]);
      }
    }

    return data;
  }`
});
console.log(result);
EOF
